import './App.css';
import React, { Component } from "react";
import CustomModal from "./components/modal";

const todoItems = [
	{
		id: 1,
		title: "Go to Market",
		description: "Buy ingredients to prepare dinnner.",
		completed: true
	},
	{
		id: 2,
		title: "Study",
		description: "Read Algebra and History textbook for upcoming test.",
		completed: false
	},
	{
		id: 3,
		title: "Sally's books",
		description: "Go to library to rent Sally's books.",
		completed: true
	},
	{
		id: 4,
		title: "Article",
		description: "Write article on how to use django with react.",
		completed: false
	},
];

export default class App extends Component {
	state = {
		modal: false,
		viewCompleted: false,
		todoList: todoItems,
		activeItem: {
			title: "",
			description: "",
			completed: false
		},
	};

	toggle() {
		this.setState({ modal: !this.state.modal });
	};

	handleSubmit = item => {
		this.toggle();
		alert("Save" + JSON.stringify(item));
	};

	handleDelete = item => {
		alert("Delete" + JSON.stringify(item));
	};

	createItem = () =>{
		const item = { title: "", description: "", completed: false };
		this.setState({	activeItem: item, modal: !this.state.modal });
	};

	editItem = item => {
		this.setState({	activeItem: item, modal: !this.state.modal });
	};

	renderTabList = () => {
		return (
			<div className="my-5 tab-list">
				<span onClick={() => this.setState({ viewCompleted: true })} className={this.state.viewCompleted ? "active" : ""}>
					Complete
				</span>
				<span onClick={() => this.setState({ viewCompleted: false })} className={this.state.viewCompleted ? "" : "active"}>
					Incomplete
				</span>
			</div>
		);
	};

	renderItems = () => {
		const { viewCompleted } = this.state;
		const newItems = this.state.todoList.filter(
			item => item.completed === viewCompleted
		);
		return newItems.map(item => (
			<li key={item.id} className="list-group-item d-flex justify-content-between align-items-center">
				<span className='todo-tile mr-2 $ {this.state.viewCompleted ? "completed-todo" : ""}' title={item.description}>
					{item.title}
				</span>
				<span>
		<button onCLick={() => this.editItem(item)}  className="btn btn-secondary mr-2">{this.state.modal ? "Editing" : "Edit"}</button>
					<button onClick={() => this.handleDelete(item)} className="btn btn-danger">Delete</button>
				</span>
			</li>
		));
	};

	render() {
		return (
			<main className="content">
				<h1 className="text-white text-uppercase text-center my-4">ToDo App</h1>
				<div className="row">
					<div className="col-md-6 col-sm-10 mx-auto p-0">
						<div className="card p-3">
							<div className="">
								<button onClick={() => this.createItem} className="btn btn-primary">Add Task</button>
							</div>
							{this.renderTabList()}
							<ul className="list-group list-group-flush">
								{this.renderItems()}
							</ul>
						</div>
					</div>
				</div>
				{this.state.modal ? (
					<CustomModal
						activeItem={this.state.activeItem}
						toggle={this.toggle}
						onSave={this.handleSubmit}
					/>
				) : null}
			</main>
		);
	};
}
